import React, { useState, useEffect } from "react";
import dft from "../../images/default.jpeg";
import Button from "../../components/Button";
import {
  IconBookmark,
  IconHeart,
  IconMessage,
  IconShare,
} from "@tabler/icons-react";
import { GridLoader } from "react-spinners";
import { useParams, useNavigate } from "react-router-dom";
const People = () => {
  const { userName } = useParams();
  const [posts, setposts] = useState([]);
  const [user, setuser] = useState([]);
  const [isFollowed, setisFollowed] = useState(false);
  const [loading, setloading] = useState(false);
  const navigate = useNavigate();
  const [commentOn, setcommentOn] = useState(false);
  const [data, setdata] = useState([]);
  const [User, setUser] = useState({});
  const [msg, setmsg] = useState("");
  const [search, setsearch] = useState("");
  useEffect(() => {
    const getPosts = async () => {
      setloading(true);
      const response = await fetch(
        `http://localhost:8000/api/people?userName=${userName}`,
        {
          method: "GET",
          headers: {
            "content-Type": "application/json",
            Authorization: `Bearer ${localStorage.getItem("user:token")}`,
          },
        }
      );
      const data = await response.json();
      console.log(data);
      setposts(data?.posts);
      setuser(data?.userDetail);
      setloading(false);
      setisFollowed(data?.isFollowed);
    };
    getPosts();
  }, []);
  const handleSearch = async () => {
    try {
      const response = await fetch("http://localhost:8000/api/search", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${localStorage.getItem("user:token")}`,
        },
        body: JSON.stringify({ search: search }),
      });
      const res = await response.json();
      if (response.status === 200) {
        navigate("/search", {
          state: {
            userFromUserName: res.usersFromUserName,
            userFromEmail: res.usersFromEmail,
          },
        });
      }
      console.log(res);
    } catch (error) {
      console.log(error);
    }
  };
  const handleSaves = async (_id, index) => {
    try {
      const response = await fetch("http://localhost:8000/api/save", {
        method: "PUT",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${localStorage.getItem("user:token")}`,
        },
        body: JSON.stringify({ id: _id }),
      });
      const updatedPost = await response.json();
      const updatePost = data?.map((post, i) => {
        if (i === index) return updatedPost;
        else return post;
      });
      setdata(updatePost);
    } catch (error) {
      console.log(error);
    }
  };
  const handleUnsaves = async (_id, index) => {
    try {
      const response = await fetch("http://localhost:8000/api/Unsave", {
        method: "PUT",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${localStorage.getItem("user:token")}`,
        },
        body: JSON.stringify({ id: _id }),
      });
      const updatedPost = await response.json();
      const updatePost = data?.map((post, i) => {
        if (i === index) return updatedPost;
        else return post;
      });
      setdata(updatePost);
    } catch (error) {
      console.log(error);
    }
  };
  const handleComment = async (_id, index, msg) => {
    try {
      const response = await fetch("http://localhost:8000/api/comment", {
        method: "PUT",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${localStorage.getItem("user:token")}`,
        },
        body: JSON.stringify({ id: _id, message: msg }),
      });
      const updatedPost = await response.json();
      const updatePost = data?.map((post, i) => {
        if (i === index) return updatedPost;
        else return post;
      });
      setdata(updatePost);
    } catch (error) {
      console.log(error);
    }
  };
  const handleLike = async (_id, index) => {
    try {
      const response = await fetch("http://localhost:8000/api/like", {
        method: "PUT",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${localStorage.getItem("user:token")}`,
        },
        body: JSON.stringify({ id: _id }),
      });
      const updatedPost = await response.json();
      const updatePost = data?.map((post, i) => {
        if (i === index) return updatedPost;
        else return post;
      });
      setdata(updatePost);
    } catch (error) {
      console.log(error);
    }
  };
  const handleUnlike = async (_id, index) => {
    const response = await fetch("http://localhost:8000/api/unlike", {
      method: "PUT",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${localStorage.getItem("user:token")}`,
      },
      body: JSON.stringify({ id: _id }),
    });
    const updatedPost = await response.json();
    const updatePost = data?.map((post, i) => {
      if (i === index) return updatedPost;
      else return post;
    });
    setdata(updatePost);
  };
  const handleUnfollow = async () => {
    const response = await fetch("http://localhost:8000/api/unfollow", {
      method: "DELETE",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${localStorage.getItem("user:token")}`,
      },
      body: JSON.stringify({ id: user.id }),
    });
    const data = await response.json();
    setisFollowed(data?.isFollowed);
    console.log(response, "resppo");
  };
  const handleFollow = async () => {
    try {
      const response = await fetch("http://localhost:8000/api/follow", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${localStorage.getItem("user:token")}`,
        },
        body: JSON.stringify({ id: user.id }),
      });

      if (!response.ok) {
        throw new Error(`Failed to follow user: ${response.status}`);
      }
      const data = await response.json();
      setisFollowed(data?.isFollowed);
      console.log("Successfully followed user");
    } catch (error) {
      console.error("Error occurred while following user:", error.message);
    }
  };
  return (
    <div className="flex justify-center items-center">
      {loading ? (
        <div className="h-[100%] flex justify-center items-center">
          <GridLoader />
        </div>
      ) : (
        <div className="border flex flex-col items-center p-10">
          <div className="flex flex-col justify-center items-center my-[6px]">
            <div className="flex flex-col my-4">
              <img
                src={user?.profilePic || dft}
                alt="Profile"
                className="w-[120px] h-[120px] mx-6 rounded-full"
              />
              <div className="flex flex-col items-center mt-[7px]">
                <p className="text-xl font-bold">{user?.userName}</p>
                <p className="text-xs font-semibold">{user?.email}</p>
              </div>
            </div>
            <div
              className="h-[50px] flex justify-around w-[300px] text-center cursor-pointer mb-[10px]"
              onClick={() => navigate("/followers")}
            >
              <div className="font-bold text-lg ">
                <h4>{user?.follower?.length || 0}</h4>
                <p>Followers</p>
              </div>
              <div className="font-bold text-lg">
                <h4>{user?.following?.length || 0}</h4>
                <p>Following</p>
              </div>
              <div className="font-bold text-lg">
                <h4>{posts.length}</h4>
                <p>Posts</p>
              </div>
            </div>
            {!isFollowed ? (
              <Button
                label="Follow"
                className="bg-[#8d91f4] hover:bg-[#525197]"
                onChange={() => handleFollow()}
              />
            ) : (
              <Button
                label="Unfollow"
                className="bg-[#8d91f4] hover:bg-[#525197]"
                onChange={() => handleUnfollow()}
              />
            )}
          </div>
          <div className="flex flex-col">
            {posts?.length > 0 &&
              posts?.map(
                (
                  {
                    _id = "",
                    caption = "",
                    description = "",
                    image = "",
                    user = {},
                    likes = [],
                    comment = [],
                    save = [],
                    isVideo = false,
                  },
                  index
                ) => {
                  const isAlreadyLiked =
                    likes.length > 0 && likes.includes(user._id);
                  return (
                    <div className="w-[500px] p-6 border rounded-lg mt-6 flex flex-col">
                      <div className="pb-4 mb-4 flex flex-col justify-center">
                        {isVideo ? (
                          <video
                            controls
                            className="w-[100%] m-0 p-0 rounded-2xl"
                          >
                            <source src={image} type="video/mp4"></source>
                          </video>
                        ) : (
                          <img
                            src={image}
                            alt="Post"
                            className="w-[100%] m-0 p-0 rounded-2xl"
                          />
                        )}
                        <div>
                          <p className="my-3 text-md font-semibold">
                            {caption}
                          </p>
                        </div>
                        <p>{description}</p>
                      </div>
                      <div className="flex justify-evenly">
                        <div
                          className="flex"
                          onClick={
                            isAlreadyLiked
                              ? () => handleUnlike(_id, index)
                              : () => handleLike(_id, index)
                          }
                        >
                          <IconHeart
                            fill={isAlreadyLiked ? "red" : "white"}
                            color={isAlreadyLiked ? "red" : "black"}
                          />
                          <p>{likes.length} </p>
                        </div>
                        <div
                          className="flex"
                          onClick={() => {
                            setcommentOn(!commentOn);
                          }}
                        >
                          <IconMessage />
                          <p>{comment.length}</p>
                        </div>
                        <div className="flex">
                          <IconShare />
                          10.5K
                        </div>
                        <div
                          className="flex"
                          onClick={() => {
                            save.length > 0 && save.includes(User._id)
                              ? handleUnsaves(_id, index)
                              : handleSaves(_id, index);
                          }}
                        >
                          <IconBookmark />
                          <p>{save.length}</p>
                        </div>
                      </div>
                    </div>
                  );
                }
              )}
          </div>
        </div>
      )}
    </div>
  );
};

export default People;
